const crypto = require('crypto');
const item = $input.first();
const headers = item.json.headers || {};
const timestamp = headers['x-slack-request-timestamp'];
const slackSignature = headers['x-slack-signature'];
const signingSecret = $env.SLACK_SIGNING_SECRET;

const rawBodyBase64 = item.binary?.data?.data;
if (!rawBodyBase64) {
  throw new Error('Raw body not found in binary data - check the Webhook node has Raw Body enabled and confirm the binary property name');
}
const rawBody = Buffer.from(rawBodyBase64, 'base64').toString('utf8');

const baseString = `v0:${timestamp}:${rawBody}`;
const computedSignature = 'v0=' + crypto.createHmac('sha256', signingSecret).update(baseString).digest('hex');
const withinTimeWindow = Math.abs((Date.now() / 1000) - Number(timestamp)) < 300;
const isValidSignature = withinTimeWindow && crypto.timingSafeEqual(Buffer.from(computedSignature), Buffer.from(slackSignature || ''));

const body = item.json.body || {};
return [{
  json: {
    isValidSignature,
    requestingUserId: body.user_id,
    originChannelId: body.channel_id,
    responseUrl: body.response_url
  }
}];

const slugify = (s) => (s || '').toString().toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

const item = $input.first().json;

const accountSlug = slugify(item.accountName);
const oppSlug = slugify(item.oppName);
const channelName = `opp-${accountSlug}-${oppSlug}`.slice(0, 80);

return [{
  json: {
    ...item,
    channelName,
    channelTopic: `${item.oppName} - ${item.stageName}`
  }
}];

const f = $('Extract Opportunity Fields').item.json;
const channelId = $('Create Slack Channel').item.json.id;
const emails = [f.accountExecutiveEmail, f.salesManagerEmail, f.salesEngineerManagerEmail, f.primarySeEmail, f.secondarySeEmail].filter(Boolean);
return emails.map(email => ({ json: { email, channelId } }));
